 {"id":"frankenjax-l3yy","title":"Preserve reduce_window integer literal dtype","description":"fj-lax reduce_window currently routes integer tensors through f64 accumulation and emits F64Bits for non-empty outputs. Preserve I64/U32/U64 literal representation with wrapping integer sum and exact min/max coverage.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-04-30T22:20:42.552787836Z","created_by":"ubuntu","updated_at":"2026-04-30T22:26:06.610817906Z","closed_at":"2026-04-30T22:26:06.609028959Z","close_reason":"Completed reduce_window integer accumulator/literal preservation for I64/U32/U64 with wrapping sum and focused unit/conformance coverage.","source_repo":".","compaction_level":0,"original_size":0}
 {"id":"frankenjax-l3zw","title":"Fast-path native F32 scalar control-flow batching","description":"BatchTrace scalar scan/while fast paths currently handle I64 and F64 literals directly but native F32Bits scalar lanes fall back to generic per-element control-flow batching. Add measured native F32 handling for scan/while scalar loops while preserving F32 literal width, add focused parity tests, benchmark before/after, and validate workspace gates.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-04-28T20:23:58.073208957Z","created_by":"ubuntu","updated_at":"2026-04-28T20:31:49.500889090Z","closed_at":"2026-04-28T20:31:49.499059363Z","close_reason":"Fast-pathed native F32 scalar scan/while batching while preserving F32Bits width; benchmarked F32 scan from ~445.8us to ~115.9us and F32 while from ~635.0us to ~84.7us; workspace fmt/check/clippy/test pass on current HEAD.","source_repo":".","compaction_level":0,"original_size":0}
+{"id":"frankenjax-l4cl","title":"Reduce unary elementwise vector allocation overhead","description":"Optimize fj-lax non-complex unary elementwise tensor hot paths by preallocating output vectors and pushing mapped literals directly instead of collecting iterator Result<Vec<_>>, preserving dtype behavior and error semantics.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-04-30T23:54:51.746287221Z","created_by":"ubuntu","updated_at":"2026-04-30T23:59:20.660803786Z","closed_at":"2026-04-30T23:59:20.659032261Z","close_reason":"Completed unary elementwise preallocated output loop optimization; sin_1k improved about 54.2% and exp_1k improved about 68.0% while preserving dtype and error semantics.","source_repo":".","compaction_level":0,"original_size":0}
 {"id":"frankenjax-l5hb","title":"Harden sort and argsort stride arithmetic","description":"sort/argsort still compute non-empty row-major strides and flat offsets with unchecked usize arithmetic. Harden the path while preserving existing empty-tensor behavior and add targeted coverage.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-04-29T20:08:51.013004327Z","created_by":"ubuntu","updated_at":"2026-04-29T20:25:30.632862204Z","closed_at":"2026-04-29T20:25:30.631041131Z","close_reason":"Hardened sort/argsort stride and flat-offset arithmetic, added empty-huge/adversarial coverage, and restored workspace gates","source_repo":".","compaction_level":0,"original_size":0}
 {"id":"frankenjax-l9oo","title":"Reduce binary elementwise vector allocation overhead","description":"Optimize fj-lax same-shape and scalar-tensor binary elementwise evaluator hot paths by preallocating output vectors and pushing results directly instead of collecting iterator Result<Vec<_>>, preserving dtype promotion and broadcasting semantics.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-04-30T23:41:43.268214326Z","created_by":"ubuntu","updated_at":"2026-04-30T23:46:36.211855501Z","closed_at":"2026-04-30T23:46:36.210022418Z","close_reason":"Completed binary elementwise preallocated output loop optimization; benchmarks improved add about 31.9% and mul about 43.4%","source_repo":".","compaction_level":0,"original_size":0}
